static char *trim_left(char *text) {
    while (*text && isspace((unsigned char)*text)) {
        text++;
    }
    return text;
}

static void trim_right(char *text) {
    size_t len = strlen(text);
    while (len > 0 && isspace((unsigned char)text[len - 1])) {
        text[len - 1] = '\0';
        len--;
    }
}

static int parse_int_token(char **cursor, int *out_value) {
    char *start;
    char *end;
    long value;

    if (!cursor || !*cursor || !out_value) {
        return 0;
    }
    start = trim_left(*cursor);
    if (!*start) {
        return 0;
    }
    value = strtol(start, &end, 10);
    if (start == end) {
        return 0;
    }
    *out_value = (int)value;
    *cursor = end;
    return 1;
}

static char *next_word(char **cursor) {
    char *start;
    char *end;

    if (!cursor || !*cursor) {
        return NULL;
    }
    start = trim_left(*cursor);
    if (!*start) {
        return NULL;
    }
    end = start;
    while (*end && !isspace((unsigned char)*end)) {
        end++;
    }
    if (*end) {
        *end = '\0';
        end++;
    }
    *cursor = end;
    return start;
}

static void print_summary(const TaskList *list) {
    printf(
        "summary total=%zu todo=%zu doing=%zu done=%zu estimate=%d remaining=%d\n",
        list->len,
        tasklist_count_status(list, TASK_TODO),
        tasklist_count_status(list, TASK_DOING),
        tasklist_count_status(list, TASK_DONE),
        tasklist_total_estimate(list, TASK_TODO, 0),
        tasklist_total_estimate(list, TASK_DONE, 0) -
            tasklist_total_estimate(list, TASK_DONE, 1)
    );
}

static void print_list(TaskList *list) {
    size_t i;
    char line[512];

    tasklist_sort_by_priority(list);
    for (i = 0; i < list->len; i++) {
        if (tasklist_format_task(&list->items[i], line, sizeof(line))) {
            printf("%s\n", line);
        }
    }
}

static int handle_command(TaskList *list, char *line) {
    char *cursor = line;
    char *command = next_word(&cursor);

    if (!command || command[0] == '#') {
        return 1;
    }
    if (strcmp(command, "add") == 0) {
        int priority;
        int estimate;
        char *title;
        Task *task;
        if (!parse_int_token(&cursor, &priority) || !parse_int_token(&cursor, &estimate)) {
            fprintf(stderr, "error: add expects priority estimate title\n");
            return 0;
        }
        title = trim_left(cursor);
        trim_right(title);
        task = tasklist_add(list, title, priority, estimate);
        if (!task) {
            fprintf(stderr, "error: invalid task\n");
            return 0;
        }
        printf("added #%d\n", task->id);
        return 1;
    }
    if (strcmp(command, "start") == 0 || strcmp(command, "done") == 0 || strcmp(command, "reopen") == 0) {
        int id;
        TaskStatus status = TASK_TODO;
        if (!parse_int_token(&cursor, &id)) {
            fprintf(stderr, "error: %s expects id\n", command);
            return 0;
        }
        if (strcmp(command, "start") == 0) {
            status = TASK_DOING;
        } else if (strcmp(command, "done") == 0) {
            status = TASK_DONE;
        }
        if (!tasklist_set_status(list, id, status)) {
            fprintf(stderr, "error: task #%d not found\n", id);
            return 0;
        }
        printf("%s #%d\n", task_status_name(status), id);
        return 1;
    }
    if (strcmp(command, "remove") == 0) {
        int id;
        if (!parse_int_token(&cursor, &id)) {
            fprintf(stderr, "error: remove expects id\n");
            return 0;
        }
        if (!tasklist_remove(list, id)) {
            fprintf(stderr, "error: task #%d not found\n", id);
            return 0;
        }
        printf("removed #%d\n", id);
        return 1;
    }
    if (strcmp(command, "list") == 0) {
        print_list(list);
        return 1;
    }
    if (strcmp(command, "summary") == 0) {
        print_summary(list);
        return 1;
    }
    if (strcmp(command, "best") == 0) {
        const Task *best = tasklist_highest_priority_open(list);
        char formatted[512];
        if (!best) {
            printf("best none\n");
            return 1;
        }
        tasklist_format_task(best, formatted, sizeof(formatted));
        printf("best %s\n", formatted);
        return 1;
    }
    if (strcmp(command, "dump") == 0) {
        char dump[4096];
        if (!tasklist_serialize(list, dump, sizeof(dump))) {
            fprintf(stderr, "error: dump buffer too small\n");
            return 0;
        }
        printf("%s", dump);
        return 1;
    }
    fprintf(stderr, "error: unknown command '%s'\n", command);
    return 0;
}

int main(int argc, char **argv) {
    FILE *input = stdin;
    TaskList list;
    char line[1024];
    int ok = 1;

    if (argc > 2) {
        fprintf(stderr, "usage: %s [script]\n", argv[0]);
        return 2;
    }
    if (argc == 2) {
        input = fopen(argv[1], "r");
        if (!input) {
            perror(argv[1]);
            return 2;
        }
    }
    tasklist_init(&list);
    while (fgets(line, sizeof(line), input)) {
        char *clean = trim_left(line);
        trim_right(clean);
        if (!handle_command(&list, clean)) {
            ok = 0;
            break;
        }
    }
    if (input != stdin) {
        fclose(input);
    }
    tasklist_free(&list);
    return ok ? 0 : 1;
}

static char *tf_strdup(const char *text) {
    size_t len;
    char *copy;

    if (!text) {
        text = "";
    }
    len = strlen(text);
    copy = (char *)malloc(len + 1);
    if (!copy) {
        return NULL;
    }
    memcpy(copy, text, len + 1);
    return copy;
}

static int tf_is_blank(const char *text) {
    const unsigned char *p = (const unsigned char *)text;
    if (!p) {
        return 1;
    }
    while (*p) {
        if (!isspace(*p)) {
            return 0;
        }
        p++;
    }
    return 1;
}

static int tf_valid_priority(int priority) {
    return priority >= 1 && priority <= 5;
}

static int tf_valid_estimate(int estimate) {
    return estimate >= 0 && estimate <= 9999;
}

static int tasklist_reserve(TaskList *list, size_t needed) {
    size_t new_cap;
    Task *new_items;

    if (!list) {
        return 0;
    }
    if (needed <= list->cap) {
        return 1;
    }
    new_cap = list->cap ? list->cap : 4;
    while (new_cap < needed) {
        new_cap *= 2;
    }
    new_items = (Task *)realloc(list->items, new_cap * sizeof(Task));
    if (!new_items) {
        return 0;
    }
    list->items = new_items;
    list->cap = new_cap;
    return 1;
}

void tasklist_init(TaskList *list) {
    if (!list) {
        return;
    }
    list->items = NULL;
    list->len = 0;
    list->cap = 0;
    list->next_id = 1;
}

void tasklist_free(TaskList *list) {
    size_t i;

    if (!list) {
        return;
    }
    for (i = 0; i < list->len; i++) {
        free(list->items[i].title);
        list->items[i].title = NULL;
    }
    free(list->items);
    list->items = NULL;
    list->len = 0;
    list->cap = 0;
    list->next_id = 1;
}

const char *task_status_name(TaskStatus status) {
    switch (status) {
        case TASK_TODO:
            return "todo";
        case TASK_DOING:
            return "doing";
        case TASK_DONE:
            return "done";
        default:
            return "unknown";
    }
}

int task_status_parse(const char *text, TaskStatus *out_status) {
    if (!text || !out_status) {
        return 0;
    }
    if (strcmp(text, "todo") == 0) {
        *out_status = TASK_TODO;
        return 1;
    }
    if (strcmp(text, "doing") == 0) {
        *out_status = TASK_DOING;
        return 1;
    }
    if (strcmp(text, "done") == 0) {
        *out_status = TASK_DONE;
        return 1;
    }
    return 0;
}

Task *tasklist_add(TaskList *list, const char *title, int priority, int estimate) {
    Task *task;
    char *title_copy;

    if (!list || tf_is_blank(title) || !tf_valid_priority(priority) || !tf_valid_estimate(estimate)) {
        return NULL;
    }
    if (!tasklist_reserve(list, list->len + 1)) {
        return NULL;
    }
    title_copy = tf_strdup(title);
    if (!title_copy) {
        return NULL;
    }
    task = &list->items[list->len++];
    task->id = list->next_id++;
    task->title = title_copy;
    task->priority = priority;
    task->estimate = estimate;
    task->status = TASK_TODO;
    return task;
}

Task *tasklist_find(TaskList *list, int id) {
    size_t i;

    if (!list) {
        return NULL;
    }
    for (i = 0; i < list->len; i++) {
        if (list->items[i].id == id) {
            return &list->items[i];
        }
    }
    return NULL;
}

const Task *tasklist_find_const(const TaskList *list, int id) {
    size_t i;

    if (!list) {
        return NULL;
    }
    for (i = 0; i < list->len; i++) {
        if (list->items[i].id == id) {
            return &list->items[i];
        }
    }
    return NULL;
}

int tasklist_remove(TaskList *list, int id) {
    size_t i;

    if (!list) {
        return 0;
    }
    for (i = 0; i < list->len; i++) {
        if (list->items[i].id == id) {
            free(list->items[i].title);
            if (i + 1 < list->len) {
                memmove(&list->items[i], &list->items[i + 1], (list->len - i - 1) * sizeof(Task));
            }
            list->len--;
            return 1;
        }
    }
    return 0;
}

int tasklist_set_status(TaskList *list, int id, TaskStatus status) {
    Task *task = tasklist_find(list, id);
    if (!task) {
        return 0;
    }
    if (status != TASK_TODO && status != TASK_DOING && status != TASK_DONE) {
        return 0;
    }
    task->status = status;
    return 1;
}

size_t tasklist_count_status(const TaskList *list, TaskStatus status) {
    size_t i;
    size_t count = 0;

    if (!list) {
        return 0;
    }
    for (i = 0; i < list->len; i++) {
        if (list->items[i].status == status) {
            count++;
        }
    }
    return count;
}

int tasklist_total_estimate(const TaskList *list, TaskStatus status, int filter_by_status) {
    size_t i;
    int total = 0;

    if (!list) {
        return 0;
    }
    for (i = 0; i < list->len; i++) {
        if (!filter_by_status || list->items[i].status == status) {
            total += list->items[i].estimate;
        }
    }
    return total;
}

const Task *tasklist_highest_priority_open(const TaskList *list) {
    size_t i;
    const Task *best = NULL;

    if (!list) {
        return NULL;
    }
    for (i = 0; i < list->len; i++) {
        const Task *task = &list->items[i];
        if (task->status == TASK_DONE) {
            continue;
        }
        if (!best ||
            task->priority > best->priority ||
            (task->priority == best->priority && task->estimate < best->estimate) ||
            (task->priority == best->priority && task->estimate == best->estimate && task->id < best->id)) {
            best = task;
        }
    }
    return best;
}

static int compare_task_priority(const Task *a, const Task *b) {
    if (a->status != b->status) {
        return (int)a->status - (int)b->status;
    }
    if (a->priority != b->priority) {
        return b->priority - a->priority;
    }
    if (a->estimate != b->estimate) {
        return a->estimate - b->estimate;
    }
    return a->id - b->id;
}

void tasklist_sort_by_priority(TaskList *list) {
    size_t i;
    int changed;

    if (!list || list->len < 2) {
        return;
    }
    do {
        changed = 0;
        for (i = 1; i < list->len; i++) {
            if (compare_task_priority(&list->items[i - 1], &list->items[i]) > 0) {
                Task tmp = list->items[i - 1];
                list->items[i - 1] = list->items[i];
                list->items[i] = tmp;
                changed = 1;
            }
        }
    } while (changed);
}

int tasklist_format_task(const Task *task, char *buffer, size_t buffer_size) {
    int written;

    if (!task || !buffer || buffer_size == 0) {
        return 0;
    }
    written = snprintf(
        buffer,
        buffer_size,
        "#%d [%s] P%d %dh %s",
        task->id,
        task_status_name(task->status),
        task->priority,
        task->estimate,
        task->title ? task->title : ""
    );
    return written >= 0 && (size_t)written < buffer_size;
}

static int append_char(char *buffer, size_t buffer_size, size_t *offset, char ch) {
    if (*offset + 1 >= buffer_size) {
        return 0;
    }
    buffer[*offset] = ch;
    (*offset)++;
    buffer[*offset] = '\0';
    return 1;
}

static int append_text(char *buffer, size_t buffer_size, size_t *offset, const char *text) {
    while (text && *text) {
        if (!append_char(buffer, buffer_size, offset, *text)) {
            return 0;
        }
        text++;
    }
    return 1;
}

static int append_escaped(char *buffer, size_t buffer_size, size_t *offset, const char *text) {
    const char *p = text ? text : "";

    while (*p) {
        if (*p == '\\' || *p == '|') {
            if (!append_char(buffer, buffer_size, offset, '\\')) {
                return 0;
            }
            if (!append_char(buffer, buffer_size, offset, *p)) {
                return 0;
            }
        } else if (*p == '\n') {
            if (!append_text(buffer, buffer_size, offset, "\\n")) {
                return 0;
            }
        } else {
            if (!append_char(buffer, buffer_size, offset, *p)) {
                return 0;
            }
        }
        p++;
    }
    return 1;
}

int tasklist_serialize(const TaskList *list, char *buffer, size_t buffer_size) {
    size_t i;
    size_t offset = 0;

    if (!list || !buffer || buffer_size == 0) {
        return 0;
    }
    buffer[0] = '\0';
    for (i = 0; i < list->len; i++) {
        char header[96];
        int written = snprintf(
            header,
            sizeof(header),
            "%d|%d|%d|%s|",
            list->items[i].id,
            list->items[i].priority,
            list->items[i].estimate,
            task_status_name(list->items[i].status)
        );
        if (written < 0 || (size_t)written >= sizeof(header)) {
            return 0;
        }
        if (!append_text(buffer, buffer_size, &offset, header)) {
            return 0;
        }
        if (!append_escaped(buffer, buffer_size, &offset, list->items[i].title)) {
            return 0;
        }
        if (!append_char(buffer, buffer_size, &offset, '\n')) {
            return 0;
        }
    }
    return 1;
}

static int split_serialized_line(const char *line, char fields[5][256]) {
    int field = 0;
    size_t offset = 0;
    const char *p = line;

    memset(fields, 0, 5 * 256);
    while (*p && *p != '\n' && *p != '\r') {
        if (*p == '\\') {
            p++;
            if (*p == 'n') {
                fields[field][offset++] = '\n';
            } else if (*p) {
                fields[field][offset++] = *p;
            }
        } else if (*p == '|' && field < 4) {
            fields[field][offset] = '\0';
            field++;
            offset = 0;
        } else {
            if (offset + 1 >= 256) {
                return 0;
            }
            fields[field][offset++] = *p;
        }
        if (offset + 1 >= 256) {
            return 0;
        }
        if (*p) {
            p++;
        }
    }
    fields[field][offset] = '\0';
    return field == 4;
}

int tasklist_load_line(TaskList *list, const char *line) {
    char fields[5][256];
    TaskStatus status;
    Task *task;
    int id;
    int priority;
    int estimate;

    if (!list || !line || tf_is_blank(line)) {
        return 0;
    }
    if (!split_serialized_line(line, fields)) {
        return 0;
    }
    id = atoi(fields[0]);
    priority = atoi(fields[1]);
    estimate = atoi(fields[2]);
    if (id <= 0 || !tf_valid_priority(priority) || !tf_valid_estimate(estimate)) {
        return 0;
    }
    if (!task_status_parse(fields[3], &status)) {
        return 0;
    }
    task = tasklist_add(list, fields[4], priority, estimate);
    if (!task) {
        return 0;
    }
    task->id = id;
    task->status = status;
    if (list->next_id <= id) {
        list->next_id = id + 1;
    }
    return 1;
}

int tasklist_load_text(TaskList *list, const char *text) {
    const char *start;
    const char *end;
    char line[512];

    if (!list || !text) {
        return 0;
    }
    start = text;
    while (*start) {
        size_t len;
        end = strchr(start, '\n');
        if (!end) {
            end = start + strlen(start);
        }
        len = (size_t)(end - start);
        if (len >= sizeof(line)) {
            return 0;
        }
        memcpy(line, start, len);
        line[len] = '\0';
        if (!tf_is_blank(line) && !tasklist_load_line(list, line)) {
            return 0;
        }
        start = *end == '\n' ? end + 1 : end;
    }
    return 1;
}

static void test_add_find_and_status_counts(void) {
    TaskList list;
    Task *a;
    Task *b;
    Task *c;

    tasklist_init(&list);
    a = tasklist_add(&list, "write parser", 5, 3);
    b = tasklist_add(&list, "build tests", 4, 2);
    c = tasklist_add(&list, "ship release", 3, 1);

    CHECK(a != NULL);
    CHECK(b != NULL);
    CHECK(c != NULL);
    CHECK(list.len == 3);
    CHECK(a->id == 1);
    CHECK(b->id == 2);
    CHECK(tasklist_find(&list, 2) == b);
    CHECK(tasklist_find(&list, 99) == NULL);
    CHECK(tasklist_count_status(&list, TASK_TODO) == 3);

    CHECK(tasklist_set_status(&list, 2, TASK_DOING));
    CHECK(tasklist_set_status(&list, 3, TASK_DONE));
    CHECK(tasklist_count_status(&list, TASK_TODO) == 1);
    CHECK(tasklist_count_status(&list, TASK_DOING) == 1);
    CHECK(tasklist_count_status(&list, TASK_DONE) == 1);
    CHECK(tasklist_total_estimate(&list, TASK_TODO, 0) == 6);
    CHECK(tasklist_total_estimate(&list, TASK_DONE, 1) == 1);

    tasklist_free(&list);
}

static void test_validation_and_remove(void) {
    TaskList list;
    Task *first;
    Task *second;
    int first_id;
    int second_id;

    tasklist_init(&list);
    CHECK(tasklist_add(&list, "", 3, 1) == NULL);
    CHECK(tasklist_add(&list, "bad priority", 0, 1) == NULL);
    CHECK(tasklist_add(&list, "bad estimate", 3, -1) == NULL);

    first = tasklist_add(&list, "first", 2, 4);
    second = tasklist_add(&list, "second", 5, 1);
    CHECK(first != NULL);
    CHECK(second != NULL);
    CHECK(list.len == 2);
    first_id = first->id;
    second_id = second->id;
    CHECK(tasklist_remove(&list, first_id));
    CHECK(list.len == 1);
    CHECK(tasklist_find(&list, first_id) == NULL);
    CHECK(tasklist_find(&list, second_id) != NULL);
    CHECK(!tasklist_remove(&list, 404));

    tasklist_free(&list);
}

static void test_highest_priority_and_sorting(void) {
    TaskList list;
    const Task *best;

    tasklist_init(&list);
    tasklist_add(&list, "low priority", 1, 5);
    tasklist_add(&list, "urgent long", 5, 8);
    tasklist_add(&list, "urgent short", 5, 2);
    tasklist_add(&list, "medium", 3, 1);
    CHECK(tasklist_set_status(&list, 3, TASK_DOING));

    best = tasklist_highest_priority_open(&list);
    CHECK(best != NULL);
    CHECK(strcmp(best->title, "urgent short") == 0);

    CHECK(tasklist_set_status(&list, best->id, TASK_DONE));
    best = tasklist_highest_priority_open(&list);
    CHECK(best != NULL);
    CHECK(strcmp(best->title, "urgent long") == 0);

    tasklist_sort_by_priority(&list);
    CHECK(strcmp(list.items[0].title, "urgent long") == 0);
    CHECK(strcmp(list.items[list.len - 1].title, "urgent short") == 0);

    tasklist_free(&list);
}

static void test_format_and_status_parse(void) {
    TaskList list;
    TaskStatus status;
    Task *task;
    char buffer[128];

    tasklist_init(&list);
    task = tasklist_add(&list, "document api", 2, 6);
    CHECK(task != NULL);
    CHECK(task_status_parse("todo", &status));
    CHECK(status == TASK_TODO);
    CHECK(task_status_parse("doing", &status));
    CHECK(status == TASK_DOING);
    CHECK(task_status_parse("done", &status));
    CHECK(status == TASK_DONE);
    CHECK(!task_status_parse("blocked", &status));

    CHECK(tasklist_format_task(task, buffer, sizeof(buffer)));
    CHECK(strstr(buffer, "#1 [todo] P2 6h document api") != NULL);
    CHECK(!tasklist_format_task(task, buffer, 4));

    tasklist_free(&list);
}

static void test_serialize_and_load_roundtrip(void) {
    TaskList original;
    TaskList loaded;
    char dump[2048];
    char dump_again[2048];
    const Task *task;

    tasklist_init(&original);
    tasklist_init(&loaded);
    tasklist_add(&original, "escape | pipe", 4, 3);
    tasklist_add(&original, "escape slash \\ value", 2, 5);
    tasklist_add(&original, "line\nbreak", 3, 1);
    CHECK(tasklist_set_status(&original, 2, TASK_DOING));
    CHECK(tasklist_set_status(&original, 3, TASK_DONE));

    CHECK(tasklist_serialize(&original, dump, sizeof(dump)));
    CHECK(strstr(dump, "escape \\| pipe") != NULL);
    CHECK(strstr(dump, "line\\nbreak") != NULL);
    CHECK(tasklist_load_text(&loaded, dump));
    CHECK(loaded.len == original.len);

    task = tasklist_find_const(&loaded, 1);
    CHECK(task != NULL);
    CHECK(strcmp(task->title, "escape | pipe") == 0);
    task = tasklist_find_const(&loaded, 2);
    CHECK(task != NULL);
    CHECK(task->status == TASK_DOING);
    CHECK(strcmp(task->title, "escape slash \\ value") == 0);
    task = tasklist_find_const(&loaded, 3);
    CHECK(task != NULL);
    CHECK(task->status == TASK_DONE);
    CHECK(strcmp(task->title, "line\nbreak") == 0);

    CHECK(tasklist_serialize(&loaded, dump_again, sizeof(dump_again)));
    CHECK(strcmp(dump, dump_again) == 0);

    tasklist_free(&original);
    tasklist_free(&loaded);
}

static void test_load_rejects_bad_lines(void) {
    TaskList list;

    tasklist_init(&list);
    CHECK(!tasklist_load_line(&list, "not|enough|fields"));
    CHECK(!tasklist_load_line(&list, "0|3|1|todo|bad id"));
    CHECK(!tasklist_load_line(&list, "1|9|1|todo|bad priority"));
    CHECK(!tasklist_load_line(&list, "1|3|-1|todo|bad estimate"));
    CHECK(!tasklist_load_line(&list, "1|3|1|blocked|bad status"));
    CHECK(list.len == 0);
    tasklist_free(&list);
}

